1	#!/usr/bin/env node
2	/**
3	 * RLM (Recursive Language Model) Hook for Claude Code
4	 *
5	 * Preresearch hook: runs Haiku before Opus/Sonnet to explore the codebase
6	 * and inject relevant context into the conversation.
7	 *
8	 * Usage:
9	 *   echo '{"prompt":"...","cwd":"/path/to/project"}' | node rlm-hook.mjs
10	 *   node rlm-hook.mjs --version
11	 *
12	 * chmod +x rlm-hook.mjs
13	 */
14	
15	import { spawn, execSync } from 'child_process';
16	import { createHash } from 'crypto';
17	import { mkdir, readFile, writeFile, stat, rm, rename } from 'fs/promises';
18	import { join, basename } from 'path';
19	import { existsSync } from 'fs';
20	import { homedir } from 'os';
21	
22	// --version flag
23	if (process.argv.includes('--version')) {
24	  console.log('0.1.0');
25	  process.exit(0);
26	}
27	
28	// Expand leading ~/ to the home directory (Node.js does not do shell tilde expansion)
29	const expandTilde = p => (p && p.startsWith('~/')) ? join(homedir(), p.slice(2)) : p;
30	
31	// Configuration — all values overridable via environment variables
32	const CONFIG = {
33	  minInputLength: parseInt(process.env.RLM_MIN_LENGTH || '20', 10),
34	  maxInputLength: parseInt(process.env.RLM_MAX_LENGTH || '4000', 10),
35	  cacheTTL: parseInt(process.env.RLM_CACHE_TTL || '3600', 10), // seconds
36	  haikuModel: process.env.RLM_MODEL || 'claude-haiku-4-5-20251001',
37	  timeout: parseInt(process.env.RLM_TIMEOUT || '60000', 10), // ms
38	  cacheDir: expandTilde(process.env.RLM_CACHE_DIR) || join(homedir(), '.cache', 'rlm-hook'),
39	  logFile: expandTilde(process.env.RLM_LOG_FILE) || join(homedir(), '.local', 'share', 'rlm-hook', 'rlm-hook.log'),
40	  // Agentic mode: allow Haiku to use tools (Read, Glob, Grep, Write, Bash) to explore the codebase
41	  agenticMode: process.env.RLM_AGENTIC_MODE !== 'false',
42	  // Max turns for agentic exploration (each turn = one tool call cycle)
43	  maxTurns: parseInt(process.env.RLM_MAX_TURNS || '10', 10),
44	  // Fast mode: concise prompt (~3s) vs detailed (~9s). Default: fast
45	  fastMode: process.env.RLM_FAST_MODE !== 'false',
46	  // Context gathering: detect project type, git state, recent files
47	  gatherContext: process.env.RLM_GATHER_CONTEXT !== 'false',
48	  // Debug mode
49	  debug: process.env.RLM_DEBUG === 'true',
50	};
51	
52	// =============================================================================
53	// LOGGING
54	// =============================================================================
55	
56	async function log(message) {
57	  const timestamp = new Date().toISOString();
58	  const entry = `[${timestamp}] ${message}\n`;
59	  try {
60	    const logDir = join(homedir(), '.local', 'share', 'rlm-hook');
61	    await mkdir(logDir, { recursive: true });
62	    await writeFile(CONFIG.logFile, entry, { flag: 'a' });
63	  } catch {
64	    // Ignore logging errors — never block the conversation
65	  }
66	}
67	
68	// =============================================================================
69	// CACHE
70	// =============================================================================
71	
72	function getCacheKey(input) {
73	  return createHash('sha256').update(input).digest('hex');
74	}
75	
76	async function checkCache(key) {
77	  const cacheFile = join(CONFIG.cacheDir, `${key}.json`);
78	  try {
79	    const stats = await stat(cacheFile);
80	    const ageSeconds = (Date.now() - stats.mtimeMs) / 1000;
81	    if (ageSeconds < CONFIG.cacheTTL) {
82	      const content = await readFile(cacheFile, 'utf-8');
83	      return JSON.parse(content);
84	    }
85	    await rm(cacheFile, { force: true });
86	  } catch {
87	    // Cache miss
88	  }
89	  return null;
90	}
91	
92	async function saveCache(key, data) {
93	  await mkdir(CONFIG.cacheDir, { recursive: true });
94	  const cacheFile = join(CONFIG.cacheDir, `${key}.json`);
95	  const tmp = `${cacheFile}.${process.pid}.tmp`;
96	  await writeFile(tmp, JSON.stringify(data, null, 2));
97	  await rename(tmp, cacheFile);
98	}
99	
100	// =============================================================================
101	// SKIP DETECTION
102	// =============================================================================
103	
104	function shouldSkipRLM(input) {
105	  if (input.length < CONFIG.minInputLength) {
106	    return { skip: true, reason: 'Input too short' };
107	  }
108	
109	  // Simple commands and single-word responses
110	  const simplePatterns = [
111	    /^(ls|cd|pwd|cat|echo|git status|npm|yarn)\b/i,
112	    /^(yes|no|ok|thanks|y|n)$/i,
113	    /^\/\w+$/,  // Slash commands like /help
114	  ];
115	
116	  for (const pattern of simplePatterns) {
117	    if (pattern.test(input.trim())) {
118	      return { skip: true, reason: 'Simple command detected' };
119	    }
120	  }
121	
122	  // Code-heavy inputs (>50% code blocks with multiple blocks) — already structured
123	  const codeBlockMatches = input.match(/```[\s\S]*?```/g) || [];
124	  const codeLength = codeBlockMatches.reduce((sum, block) => sum + block.length, 0);
125	  if (codeLength > input.length * 0.5 && codeBlockMatches.length > 1) {
126	    return { skip: true, reason: 'Code-heavy input' };
127	  }
128	
129	  return { skip: false };
130	}
131	
132	// =============================================================================
133	// CONTEXT GATHERING
134	// =============================================================================
135	
136	async function gatherProjectContext(cwd) {
137	  if (!cwd || !existsSync(cwd)) return null;
138	
139	  const context = {
140	    projectRoot: cwd,
141	    projectName: basename(cwd),
142	    projectType: null,
143	    techStack: [],
144	    recentFiles: [],
145	    gitBranch: null,
146	    gitStatus: null,
147	  };
148	
149	  try {
150	    const manifestFiles = {
151	      'package.json': 'node',
152	      'Cargo.toml': 'rust',
153	      'go.mod': 'go',
154	      'pyproject.toml': 'python',
155	      'requirements.txt': 'python',
156	      'pom.xml': 'java',
157	      'build.gradle': 'java',
158	      'Gemfile': 'ruby',
159	      'composer.json': 'php',
160	    };
161	
162	    for (const [file, type] of Object.entries(manifestFiles)) {
163	      if (existsSync(join(cwd, file))) {
164	        context.projectType = type;
165	        context.techStack.push(type);
166	
167	        if (file === 'package.json') {
168	          try {
169	            const pkg = JSON.parse(await readFile(join(cwd, file), 'utf-8'));
170	            const deps = Object.keys(pkg.dependencies || {}).slice(0, 10);
171	            const devDeps = Object.keys(pkg.devDependencies || {}).slice(0, 5);
172	            context.techStack.push(...deps, ...devDeps);
173	          } catch {}
174	        }
175	        break;
176	      }
177	    }
178	
179	    // Git info (fast ops only)
180	    try {
181	      context.gitBranch = execSync('git branch --show-current 2>/dev/null', { cwd, timeout: 1000 })
182	        .toString().trim();
183	      context.gitStatus = execSync('git status --porcelain 2>/dev/null', { cwd, timeout: 1000 })
184	        .toString().trim().split('\n').slice(0, 5).join(', ');
185	    } catch {}
186	
187	    // Recent source files (fast find, no node_modules)
188	    try {
189	      const found = execSync(
190	        'find . -type f \\( -name "*.ts" -o -name "*.js" -o -name "*.mjs" -o -name "*.py" -o -name "*.rs" -o -name "*.go" \\) 2>/dev/null | grep -v node_modules | head -20',
191	        { cwd, timeout: 2000 }
192	      ).toString().trim().split('\n').filter(Boolean);
193	      context.recentFiles = found.slice(0, 10);
194	    } catch {}
195	
196	  } catch (err) {
197	    await log(`Context gathering error: ${err.message}`);
198	  }
199	
200	  return context;
201	}
202	
203	async function gatherConversationContext(transcriptPath, maxMessages = 5) {
204	  if (!transcriptPath || !existsSync(transcriptPath)) return null;
205	
206	  try {
207	    const content = await readFile(transcriptPath, 'utf-8');
208	    const lines = content.trim().split('\n').slice(-maxMessages * 2);
209	
210	    const messages = [];
211	    for (const line of lines) {
212	      try {
213	        const entry = JSON.parse(line);
214	        if (entry.type === 'user' || entry.type === 'assistant') {
215	          const raw = entry.message?.content || entry.content || '';
216	          const text = Array.isArray(raw)
217	            ? raw.filter(b => b.type === 'text').map(b => b.text).join(' ')
218	            : (typeof raw === 'string' ? raw : '');
219	          if (text) {
220	            messages.push({
221	              role: entry.type,
222	              preview: text.slice(0, 200) + (text.length > 200 ? '...' : '')
223	            });
224	          }
225	        }
226	      } catch {}
227	    }
228	
229	    return messages.slice(-maxMessages);
230	  } catch (err) {
231	    await log(`Transcript read error: ${err.message}`);
232	    return null;
233	  }
234	}
235	
236	// =============================================================================
237	// PROMPT BUILDING
238	// =============================================================================
239	
240	function buildRLMPrompt(userMessage, projectContext, conversationContext) {
241	  let contextSection = '';
242	
243	  if (projectContext) {
244	    contextSection += `\nProject: ${projectContext.projectName} (${projectContext.projectType || 'unknown'})`;
245	    if (projectContext.techStack.length > 0) {
246	      contextSection += `\nStack: ${projectContext.techStack.slice(0, 8).join(', ')}`;
247	    }
248	    if (projectContext.gitBranch) {
249	      contextSection += `\nBranch: ${projectContext.gitBranch}`;
250	    }
251	    if (projectContext.gitStatus) {
252	      contextSection += `\nModified: ${projectContext.gitStatus}`;
253	    }
254	    if (projectContext.recentFiles.length > 0) {
255	      contextSection += `\nFiles: ${projectContext.recentFiles.slice(0, 5).join(', ')}`;
256	    }
257	  }
258	
259	  if (conversationContext && conversationContext.length > 0) {
260	    contextSection += `\nRecent conversation:`;
261	    for (const msg of conversationContext.slice(-3)) {
262	      contextSection += `\n- ${msg.role}: ${msg.preview.slice(0, 100)}`;
263	    }
264	  }
265	
266	  // Agentic mode: Haiku explores the codebase with tools and writes structured notes
267	  if (CONFIG.agenticMode) {
268	    const scratchFile = '.claude/rlm-scratch.md';
269	
270	    return `You are an RLM (Recursive Language Model) preresearch agent. Your job is to explore the codebase and gather context for a more expensive coding model.
271	
272	TASK: Analyze the user's request and gather relevant context from the codebase.
273	
274	USER REQUEST: ${userMessage}
275	
276	INITIAL CONTEXT:${contextSection || ' (none provided)'}
277	
278	EXPLORATION TOOLS AVAILABLE:
279	- Glob: Find files by pattern (e.g., "src/**/*.ts", "**/auth*")
280	- Grep: Search file contents (e.g., search for "authenticate", "middleware")
281	- Read: Read specific files to understand implementation
282	- Write: Write intermediate notes to ${scratchFile}
283	- Bash: Run git commands ONLY (git log, git show, git diff, git blame)
284	
285	EXPLORATION WORKFLOW:
286	1. Start by writing your initial understanding to ${scratchFile}
287	2. Use Glob to find potentially relevant files — write findings to notes
288	3. Use Grep to search for key terms, function names, patterns — append to notes
289	4. Use Read to examine the most relevant files (max 3-5 files) — append key findings
290	5. Use git log/diff to see recent changes — append to notes
291	6. Read back your ${scratchFile} notes
292	7. Synthesize everything into a final structured JSON summary
293	8. Delete ${scratchFile} using Bash: rm ${scratchFile}
294	
295	NOTES FORMAT (${scratchFile}):
296	\`\`\`markdown
297	# RLM Preresearch Notes
298	
299	## Initial Understanding
300	[What I think the user wants]
301	
302	## File Discovery
303	[Results from Glob searches]
304	
305	## Code Patterns Found
306	[Results from Grep searches]
307	
308	## Key File Analysis
309	[Important findings from Read]
310	
311	## Git History
312	[Relevant recent changes]
313	
314	## Open Questions
315	[Things that need clarification]
316	\`\`\`
317	
318	CONSTRAINTS:
319	- Write notes incrementally as you explore — don't try to remember everything
320	- Read back your notes before synthesizing
321	- Focus on: entry points, interfaces, existing patterns, recent changes
322	- For large files, note structure and key exports rather than full content
323	
324	FINAL OUTPUT (after deleting scratch file):
325	Output ONLY this JSON structure (no markdown, no explanation):
326	{
327	  "intent": "code_writing|debugging|refactoring|architecture|learning|other",
328	  "summary": "One paragraph summary synthesized from your notes",
329	  "relevant_files": [
330	    {"path": "file/path.ts", "purpose": "what this file does", "key_exports": ["func1", "Class1"]}
331	  ],
332	  "existing_patterns": ["pattern1 used in codebase", "pattern2"],
333	  "recent_changes": "summary of relevant git history",
334	  "dependencies": ["relevant deps from package.json etc"],
335	  "tasks": ["step1", "step2", "step3"],
336	  "approach": "recommended implementation approach based on existing patterns",
337	  "warnings": ["potential issues or considerations"]
338	}
339	
340	If the request is trivial (simple command, greeting, etc.), skip exploration and output: {"skip": true, "reason": "explanation"}
341	
342	BEGIN: Write initial understanding to ${scratchFile}, then explore systematically.`;
343	  }
344	
345	  if (CONFIG.fastMode) {
346	    // Concise prompt for low-latency non-agentic analysis (~3s response)
347	    return `Analyze with project context. Output ONLY JSON, no markdown:
348	{"intent":"code_writing|debugging|architecture|learning|other","tasks":["task1","task2","task3"],"tech":["relevant","technologies"],"files":["likely_relevant_files"],"approach":"one sentence strategy"}
349	If trivial, output: {"skip":true}
350	${contextSection}
351	
352	User: ${userMessage}`;
353	  }
354	
355	  // Detailed non-agentic prompt (~9s response)
356	  return `You are an RLM (Recursive Language Model) analyzer. Analyze this user message with project context.
357	${contextSection ? `\n<project_context>${contextSection}\n</project_context>` : ''}
358	
359	<user_message>
360	${userMessage}
361	</user_message>
362	
363	Provide analysis in this exact JSON format (no markdown, just raw JSON):
364	{
365	  "intent": {
366	    "primary": "code_writing|debugging|code_review|architecture|documentation|learning|configuration|other",
367	    "secondary": [],
368	    "confidence": 0.0-1.0
369	  },
370	  "decomposition": [
371	    {"task": "description", "priority": 1-5, "dependencies": []}
372	  ],
373	  "implicit_context": {
374	    "domain": "web|backend|devops|data|ml|mobile|other",
375	    "assumed_knowledge": [],
376	    "relevant_technologies": []
377	  },
378	  "ambiguities": [
379	    {"aspect": "what's unclear", "interpretations": [], "suggested_default": ""}
380	  ],
381	  "success_criteria": [],
382	  "suggested_approach": "high-level strategy",
383	  "skip_rlm": false,
384	  "skip_reason": null
385	}
386	
387	If the query is too simple for this analysis, return: {"skip_rlm": true, "skip_reason": "reason"}
388	
389	Output ONLY valid JSON, nothing else.`;
390	}
391	
392	// =============================================================================
393	// HAIKU INVOCATION
394	// =============================================================================
395	
396	async function invokeHaiku(prompt, workingDir = null) {
397	  return new Promise((resolve, reject) => {
398	    const startTime = Date.now();
399	
400	    const args = [
401	      '-p', prompt,
402	      '--model', CONFIG.haikuModel,
403	      '--output-format', 'text',
404	    ];
405	
406	    if (workingDir) {
407	      args.push('--add-dir', workingDir);
408	    }
409	
410	    // Always bypass permissions — this is a preresearch subprocess, not an interactive session
411	    args.push('--permission-mode', 'bypassPermissions');
412	
413	    if (CONFIG.agenticMode) {
414	      // Enable file exploration tools + git + scratch file cleanup
415	      args.push('--allowedTools', 'Read,Glob,Grep,Write,Bash(git:*),Bash(rm:*)');
416	      args.push('--max-turns', String(CONFIG.maxTurns));
417	    }
418	    // Non-agentic: omit --allowedTools entirely — absence means no tools allowed
419	
420	    const proc = spawn('claude', args, {
421	      stdio: ['pipe', 'pipe', 'pipe'],
422	      cwd: workingDir || process.cwd(),
423	    });
424	
425	    let stdout = '';
426	    let stderr = '';
427	
428	    const timeoutId = setTimeout(() => {
429	      proc.kill('SIGTERM');
430	      setTimeout(() => { try { proc.kill('SIGKILL'); } catch {} }, 2000);
431	      reject(new Error('Haiku invocation timed out'));
432	    }, CONFIG.timeout);
433	
434	    proc.stdout.on('data', (data) => { stdout += data.toString(); });
435	    proc.stderr.on('data', (data) => { stderr += data.toString(); });
436	
437	    proc.on('close', (code) => {
438	      clearTimeout(timeoutId);
439	      const latency = Date.now() - startTime;
440	      log(`Haiku completed in ${latency}ms with exit code ${code}`);
441	
442	      if (code === 0) {
443	        resolve(stdout);
444	      } else {
445	        reject(new Error(`Haiku failed (exit ${code}): ${stderr.slice(0, 500)}`));
446	      }
447	    });
448	
449	    proc.on('error', (err) => {
450	      clearTimeout(timeoutId);
451	      reject(err);
452	    });
453	
454	    proc.stdin.end();
455	  });
456	}
457	
458	// =============================================================================
459	// RESPONSE PARSING
460	// =============================================================================
461	
462	function parseHaikuResponse(response) {
463	  // 1. Direct JSON parse
464	  try {
465	    return JSON.parse(response.trim());
466	  } catch {}
467	
468	  // 2. JSON inside markdown code block
469	  const jsonMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
470	  if (jsonMatch) {
471	    try {
472	      return JSON.parse(jsonMatch[1].trim());
473	    } catch {}
474	  }
475	
476	  // 3. Any JSON object in the response (non-greedy to avoid spanning multiple objects)
477	  const objectMatch = response.match(/\{[\s\S]*?\}/);
478	  if (objectMatch) {
479	    try {
480	      return JSON.parse(objectMatch[0]);
481	    } catch {}
482	  }
483	
484	  return { skip_rlm: true, skip_reason: 'Could not parse Haiku response' };
485	}
486	
487	// =============================================================================
488	// OUTPUT FORMATTING
489	// =============================================================================
490	
491	function formatOutput(analysis) {
492	  // Agentic mode produces a rich structure with relevant_files
493	  if (CONFIG.agenticMode && analysis.relevant_files) {
494	    const intent = analysis.intent || 'unknown';
495	    const summary = analysis.summary || '';
496	    const files = (analysis.relevant_files || []).map(f =>
497	      typeof f === 'string' ? f : `${f.path} (${f.purpose || 'unknown'})`
498	    ).join('; ');
499	    const patterns = (analysis.existing_patterns || []).join('; ');
500	    const tasks = (analysis.tasks || []).join('; ');
501	    const approach = analysis.approach || 'N/A';
502	    const warnings = (analysis.warnings || []).join('; ');
503	    const recentChanges = analysis.recent_changes || '';
504	
505	    let output = `<rlm_preresearch>
506	${JSON.stringify(analysis, null, 2)}
507	</rlm_preresearch>
508	
509	PRERESEARCH COMPLETE:
510	Intent: ${intent}
511	Summary: ${summary}
512	Relevant Files: ${files}
513	Existing Patterns: ${patterns}
514	Recent Changes: ${recentChanges}
515	Tasks: ${tasks}
516	Approach: ${approach}`;
517	    if (warnings) output += `\nWarnings: ${warnings}`;
518	    return output;
519	  }
520	
521	  // Fast mode: compact structure
522	  if (CONFIG.fastMode) {
523	    const intent = analysis.intent || 'unknown';
524	    const tasks = (analysis.tasks || []).join('; ');
525	    const tech = (analysis.tech || []).join(', ');
526	    const files = (analysis.files || []).join(', ');
527	    const approach = analysis.approach || 'N/A';
528	
529	    let output = `<rlm_analysis>
530	${JSON.stringify(analysis, null, 2)}
531	</rlm_analysis>
532	
533	RLM: ${intent} | Tasks: ${tasks}`;
534	    if (tech) output += ` | Tech: ${tech}`;
535	    if (files) output += ` | Files: ${files}`;
536	    output += ` | Approach: ${approach}`;
537	    return output;
538	  }
539	
540	  // Detailed mode
541	  const intent = analysis.intent?.primary || 'unknown';
542	  const confidence = analysis.intent?.confidence || 'N/A';
543	  const tasks = (analysis.decomposition || [])
544	    .slice(0, 3)
545	    .map(t => t.task)
546	    .join('; ');
547	  const approach = analysis.suggested_approach || 'N/A';
548	  const domain = analysis.implicit_context?.domain || 'general';
549	  const technologies = (analysis.implicit_context?.relevant_technologies || []).join(', ') || 'N/A';
550	
551	  return `<rlm_analysis>
552	${JSON.stringify(analysis, null, 2)}
553	</rlm_analysis>
554	
555	RLM Pre-Analysis Summary:
556	- Intent: ${intent} (confidence: ${confidence})
557	- Key Tasks: ${tasks || 'N/A'}
558	- Approach: ${approach}
559	- Domain: ${domain}
560	- Technologies: ${technologies}`;
561	}
562	
563	// =============================================================================
564	// STDIN READER
565	// =============================================================================
566	
567	async function readStdin() {
568	  const chunks = [];
569	  for await (const chunk of process.stdin) {
570	    chunks.push(chunk);
571	  }
572	  return Buffer.concat(chunks).toString('utf-8');
573	}
574	
575	// =============================================================================
576	// MAIN
577	// =============================================================================
578	
579	async function main() {
580	  try {
581	    const input = await readStdin();
582	
583	    let userMessage = input;
584	    let cwd = null;
585	    let transcriptPath = null;
586	
587	    // Claude Code hook format: JSON with prompt, cwd, transcript_path
588	    try {
589	      const hookInput = JSON.parse(input);
590	      userMessage = hookInput.prompt || hookInput.message || hookInput.input || hookInput.content || input;
591	      cwd = hookInput.cwd || null;
592	      transcriptPath = hookInput.transcript_path || null;
593	    } catch {
594	      // Fall back to treating raw input as the message
595	    }
596	
597	    await log(`Processing input of length ${userMessage.length}${cwd ? ` in ${cwd}` : ''}`);
598	
599	    // Skip detection (before cache check to avoid hashing)
600	    const skipCheck = shouldSkipRLM(userMessage);
601	    if (skipCheck.skip) {
602	      await log(`Skipping RLM: ${skipCheck.reason}`);
603	      process.exit(0);
604	    }
605	
606	    // Cache lookup — include cwd so the same prompt in different projects doesn't collide
607	    const cacheKey = getCacheKey(userMessage + '\0' + (cwd || ''));
608	    const cached = await checkCache(cacheKey);
609	    if (cached) {
610	      await log(`Cache hit for ${cacheKey.slice(0, 16)}...`);
611	      console.log(formatOutput(cached));
612	      process.exit(0);
613	    }
614	
615	    // Truncate long inputs
616	    let truncatedMessage = userMessage;
617	    if (userMessage.length > CONFIG.maxInputLength) {
618	      truncatedMessage = userMessage.slice(0, CONFIG.maxInputLength) + '... [truncated]';
619	      await log(`Input truncated to ${CONFIG.maxInputLength} characters`);
620	    }
621	
622	    // Gather project and conversation context
