1	#!/usr/bin/env node
2	/**
3	 * Comprehensive unit tests for the claude-code-rlm hook.
4	 *
5	 * Run with: node --test test/unit.test.mjs
6	 *
7	 * Logic is inlined from rlm-hook.mjs since functions are not exported.
8	 * Tests cover the 9 functional groups described in docs/plan/plan.md.
9	 */
10	
11	import { describe, it, beforeEach, afterEach } from 'node:test';
