25	/**
26	 * shouldSkipRLM — decides whether to skip the RLM pipeline entirely.
27	 * Inlined from rlm-hook.mjs with a configurable minInputLength so we can
28	 * probe the exact threshold boundary.
29	 */
30	function shouldSkipRLM(input, minInputLength = 20) {
31	  // Too short
32	  if (input.length < minInputLength) {
33	    return { skip: true, reason: 'Input too short' };
34	  }
35	
36	  // Simple commands / affirmatives / slash commands
37	  const simplePatterns = [
38	    /^(ls|cd|pwd|cat|echo|git status|npm|yarn)\b/i,
39	    /^(yes|no|ok|thanks|y|n)$/i,
40	    /^\/\w+$/,
41	  ];
42	
43	  for (const pattern of simplePatterns) {
44	    if (pattern.test(input.trim())) {
45	      return { skip: true, reason: 'Simple command detected' };
46	    }
47	  }
48	
49	  // Code-heavy: >50 % of the input is inside code fences AND there are 2+ blocks
50	  const codeBlockMatches = input.match(/```[\s\S]*?```/g) || [];
51	  const codeLength = codeBlockMatches.reduce((sum, block) => sum + block.length, 0);
52	  if (codeLength > input.length * 0.5 && codeBlockMatches.length > 1) {
53	    return { skip: true, reason: 'Code-heavy input' };
54	  }
55	
56	  return { skip: false };
57	}
58	
59	/**
60	 * getCacheKey — SHA-256 hex digest of the input string.
61	 */
62	function getCacheKey(input) {
63	  return createHash('sha256').update(input).digest('hex');
64	}
65	
66	/**
67	 * parseHaikuResponse — extracts JSON from a Haiku text response.
68	 * Tries direct parse → ```json block → embedded {} → fallback.
69	 */
70	function parseHaikuResponse(response) {
71	  try {
72	    return JSON.parse(response.trim());
73	  } catch {
74	    const jsonMatch = response.match(/```(?:json)?\s*([\s\S]*?)```/);
75	    if (jsonMatch) {
76	      try {
77	        return JSON.parse(jsonMatch[1].trim());
78	      } catch {
79	        // fall through
80	      }
81	    }
82	
83	    const objectMatch = response.match(/\{[\s\S]*\}/);
84	    if (objectMatch) {
85	      try {
86	        return JSON.parse(objectMatch[0]);
87	      } catch {
88	        // give up
89	      }
90	    }
91	
92	    return { skip_rlm: true, skip_reason: 'Could not parse response' };
93	  }
94	}
