96	/**
97	 * parseHookInput — decodes Claude Code hook stdin into (userMessage, cwd, transcriptPath).
98	 */
99	function parseHookInput(rawInput) {
100	  let userMessage = rawInput;
101	  let cwd = null;
102	  let transcriptPath = null;
103	
104	  try {
105	    const hookInput = JSON.parse(rawInput);
106	    userMessage = hookInput.prompt || hookInput.message || hookInput.input || hookInput.content || rawInput;
107	    cwd = hookInput.cwd || null;
108	    transcriptPath = hookInput.transcript_path || null;
109	  } catch {
110	    // Use raw text
111	  }
112	
113	  return { userMessage, cwd, transcriptPath };
114	}
