116	/**
117	 * truncateInput — clamps message to maxLength and appends a truncation marker.
118	 */
119	function truncateInput(message, maxLength = 4000) {
120	  if (message.length > maxLength) {
121	    return message.slice(0, maxLength) + '... [truncated]';
122	  }
123	  return message;
124	}
