126	/**
127	 * gatherProjectContext — inspects cwd for manifest files to detect project type.
128	 * Inlined minus the git / find calls that require a real repo.
129	 */
130	async function gatherProjectContext(cwd) {
131	  if (!cwd || !existsSync(cwd)) return null;
132	
133	  const context = {
134	    projectRoot: cwd,
135	    projectName: cwd.split('/').pop(),
136	    projectType: null,
137	    techStack: [],
138	    recentFiles: [],
139	    gitBranch: null,
140	    gitStatus: null,
141	  };
142	
143	  const manifestFiles = {
144	    'package.json': 'node',
145	    'Cargo.toml': 'rust',
146	    'go.mod': 'go',
147	    'pyproject.toml': 'python',
148	    'requirements.txt': 'python',
149	    'pom.xml': 'java',
150	    'build.gradle': 'java',
151	    'Gemfile': 'ruby',
152	    'composer.json': 'php',
153	  };
154	
155	  for (const [file, type] of Object.entries(manifestFiles)) {
156	    if (existsSync(join(cwd, file))) {
157	      context.projectType = type;
158	      context.techStack.push(type);
159	
160	      if (file === 'package.json') {
161	        try {
162	          const pkg = JSON.parse(await readFile(join(cwd, file), 'utf-8'));
163	          const deps = Object.keys(pkg.dependencies || {}).slice(0, 10);
164	          const devDeps = Object.keys(pkg.devDependencies || {}).slice(0, 5);
165	          context.techStack.push(...deps, ...devDeps);
166	        } catch {}
167	      }
168	      break;
169	    }
170	  }
171	
172	  return context;
173	}
