175	/**
176	 * formatOutput — renders the final text Claude Code injects before the user message.
177	 * Accepts explicit mode flags rather than reading from a global CONFIG so tests
178	 * can invoke each branch independently.
179	 */
180	function formatOutput(analysis, { agenticMode = false, fastMode = false } = {}) {
181	  // Agentic path — rich structure with relevant_files
182	  if (agenticMode && analysis.relevant_files) {
183	    const intent = analysis.intent || 'unknown';
184	    const summary = analysis.summary || '';
185	    const files = (analysis.relevant_files || [])
186	      .map(f => (typeof f === 'string' ? f : `${f.path} (${f.purpose || 'unknown'})`))
187	      .join('; ');
188	    const patterns = (analysis.existing_patterns || []).join('; ');
189	    const tasks = (analysis.tasks || []).join('; ');
190	    const approach = analysis.approach || 'N/A';
191	    const warnings = (analysis.warnings || []).join('; ');
192	    const recentChanges = analysis.recent_changes || '';
193	
194	    let output =
195	      `<rlm_preresearch>\n${JSON.stringify(analysis, null, 2)}\n</rlm_preresearch>` +
196	      `\n\nPRERESEARCH COMPLETE:` +
197	      `\nIntent: ${intent}` +
198	      `\nSummary: ${summary}` +
199	      `\nRelevant Files: ${files}` +
200	      `\nExisting Patterns: ${patterns}` +
201	      `\nRecent Changes: ${recentChanges}` +
202	      `\nTasks: ${tasks}` +
203	      `\nApproach: ${approach}`;
204	    if (warnings) output += `\nWarnings: ${warnings}`;
205	    return output;
206	  }
207	
208	  // Fast path — concise summary line
209	  if (fastMode) {
210	    const intent = analysis.intent || 'unknown';
211	    const tasks = (analysis.tasks || []).join('; ');
212	    const tech = (analysis.tech || []).join(', ');
213	    const files = (analysis.files || []).join(', ');
214	    const approach = analysis.approach || 'N/A';
215	
216	    let output =
217	      `<rlm_analysis>\n${JSON.stringify(analysis, null, 2)}\n</rlm_analysis>` +
218	      `\n\nRLM: ${intent} | Tasks: ${tasks}`;
219	    if (tech) output += ` | Tech: ${tech}`;
220	    if (files) output += ` | Files: ${files}`;
221	    output += ` | Approach: ${approach}`;
222	    return output;
223	  }
224	
225	  // Detailed / default path
226	  const intent = analysis.intent?.primary || 'unknown';
227	  const confidence = analysis.intent?.confidence ?? 'N/A';
228	  const tasks = (analysis.decomposition || []).slice(0, 3).map(t => t.task).join('; ');
229	  const approach = analysis.suggested_approach || 'N/A';
230	  const domain = analysis.implicit_context?.domain || 'general';
231	  const technologies = (analysis.implicit_context?.relevant_technologies || []).join(', ') || 'N/A';
232	
233	  return (
234	    `<rlm_analysis>\n${JSON.stringify(analysis, null, 2)}\n</rlm_analysis>` +
235	    `\n\nRLM Pre-Analysis Summary:` +
236	    `\n- Intent: ${intent} (confidence: ${confidence})` +
237	    `\n- Key Tasks: ${tasks || 'N/A'}` +
238	    `\n- Approach: ${approach}` +
239	    `\n- Domain: ${domain}` +
240	    `\n- Technologies: ${technologies}`
241	  );
242	}
