244	/**
245	 * buildRLMPrompt — composes the prompt sent to Haiku.
246	 * Takes explicit mode flags so each branch can be tested in isolation.
247	 */
248	function buildRLMPrompt(userMessage, projectContext, conversationContext, { agenticMode = false, fastMode = false } = {}) {
249	  let contextSection = '';
250	
251	  if (projectContext) {
252	    contextSection += `\nProject: ${projectContext.projectName} (${projectContext.projectType || 'unknown'})`;
253	    if (projectContext.techStack && projectContext.techStack.length > 0) {
254	      contextSection += `\nStack: ${projectContext.techStack.slice(0, 8).join(', ')}`;
255	    }
256	    if (projectContext.gitBranch) {
257	      contextSection += `\nBranch: ${projectContext.gitBranch}`;
258	    }
259	    if (projectContext.gitStatus) {
260	      contextSection += `\nModified: ${projectContext.gitStatus}`;
261	    }
262	    if (projectContext.recentFiles && projectContext.recentFiles.length > 0) {
263	      contextSection += `\nFiles: ${projectContext.recentFiles.slice(0, 5).join(', ')}`;
264	    }
265	  }
266	
267	  if (conversationContext && conversationContext.length > 0) {
268	    contextSection += `\nRecent conversation:`;
269	    for (const msg of conversationContext.slice(-3)) {
270	      contextSection += `\n- ${msg.role}: ${msg.preview.slice(0, 100)}`;
271	    }
272	  }
273	
274	  if (agenticMode) {
275	    const scratchFile = '.claude/rlm-scratch.md';
276	    return (
277	      `You are an RLM (Recursive Language Model) preresearch agent. Your job is to explore the codebase and gather context for a more expensive coding model.\n\n` +
278	      `TASK: Analyze the user's request and gather relevant context from the codebase.\n\n` +
279	      `USER REQUEST: ${userMessage}\n\n` +
280	      `INITIAL CONTEXT:${contextSection || ' (none provided)'}\n\n` +
281	      `EXPLORATION TOOLS AVAILABLE:\n` +
282	      `- Glob: Find files by pattern (e.g., "src/**/*.ts", "**/auth*")\n` +
283	      `- Grep: Search file contents (e.g., search for "authenticate", "middleware")\n` +
284	      `- Read: Read specific files to understand implementation\n` +
285	      `- Write: Write intermediate notes to ${scratchFile}\n` +
286	      `- Bash: Run git commands ONLY (git log, git show, git diff, git blame)\n\n` +
287	      `BEGIN: Write initial understanding to ${scratchFile}, then explore systematically.`
288	    );
289	  }
290	
291	  if (fastMode) {
292	    return (
293	      `Analyze with project context. Output ONLY JSON, no markdown:\n` +
294	      `{"intent":"code_writing|debugging|architecture|learning|other","tasks":["task1","task2","task3"],"tech":["relevant","technologies"],"files":["likely_relevant_files"],"approach":"one sentence strategy"}\n` +
295	      `If trivial, output: {"skip":true}\n` +
296	      `${contextSection}\n\n` +
297	      `User: ${userMessage}`
298	    );
299	  }
300	
301	  // Detailed mode
302	  return (
303	    `You are an RLM (Recursive Language Model) analyzer. Analyze this user message with project context.\n` +
304	    (contextSection ? `\n<project_context>${contextSection}\n</project_context>` : '') +
305	    `\n\n<user_message>\n${userMessage}\n</user_message>\n\n` +
306	    `Provide analysis in this exact JSON format (no markdown, just raw JSON).`
307	  );
308	}
